// Verificar si es el último día hábil del mes
const hoy = new Date();
const ultimoDia = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0);
const diaSemana = ultimoDia.getDay(); // 0=Domingo, 6=Sábado

// Si es fin de semana, retroceder al viernes anterior
let ultimoDiaHabil = ultimoDia;
if (diaSemana === 0) { // Domingo
  ultimoDiaHabil = new Date(ultimoDia.getTime() - 2 * 24 * 60 * 60 * 1000);
} else if (diaSemana === 6) { // Sábado
  ultimoDiaHabil = new Date(ultimoDia.getTime() - 1 * 24 * 60 * 60 * 1000);
}

// Verificar si hoy es el último día hábil
const hoyStr = hoy.toISOString().split('T')[0];
const ultimoDiaHabilStr = ultimoDiaHabil.toISOString().split('T')[0];

if (hoyStr !== ultimoDiaHabilStr) {
  // No es el último día hábil, no ejecutar
  return [];
}

return [{
  json: {
    es_ultimo_dia_habil: true,
    fecha: hoyStr,
    fecha_ultimo_dia: ultimoDiaHabilStr,
    mes: hoy.getMonth() + 1,
    año: hoy.getFullYear(),
    nombre_mes: hoy.toLocaleDateString('es-ES', { month: 'long' })
  }
}];

// Parsear respuesta de Supabase
const respuesta = $input.item.json;

// Si es array, usar directamente; si es objeto, convertirlo a array
let observaciones = Array.isArray(respuesta) ? respuesta : [respuesta];

// Filtrar observaciones válidas (con email y responsable)
observaciones = observaciones.filter(obs => 
  obs.responsable_implementacion_user && 
  obs.responsable_implementacion_user.email &&
  obs.responsable_implementacion
);

if (observaciones.length === 0) {
  return [];
}

// Preparar datos y determinar si es fecha final
const fechaHoy = new Date();
fechaHoy.setHours(0, 0, 0, 0);

return observaciones.map(obs => {
  // Usar nueva_fecha_implementacion si existe, sino fecha_fin
  const fechaReferencia = obs.nueva_fecha_implementacion || obs.fecha_fin;
  const fechaFin = new Date(fechaReferencia);
  fechaFin.setHours(0, 0, 0, 0);

  // Es fecha final si fecha de referencia es hoy (último día del mes)
  const esFechaFinal = fechaFin.getTime() === fechaHoy.getTime();

  return {
    json: {
      observacion_id: obs.id,
      auditoria_id: obs.auditoria_id,
      numero_observacion: obs.numero_observacion || 0,
      titulo: obs.titulo_observacion || 'Sin título',
      descripcion: obs.descripcion_observacion || 'Sin descripción',
      fecha_fin: fechaReferencia,
      es_fecha_final: esFechaFinal,
      responsable_id: obs.responsable_implementacion,
      responsable_nombre: obs.responsable_implementacion_user?.full_name || 'Responsable',
      responsable_email: obs.responsable_implementacion_user?.email || '',
      auditoria_nombre: obs.auditoria?.nombre || 'Auditoría',
      auditoria_estado: obs.auditoria?.estado || 'EN_PROCESO',
      porcentaje_avance: obs.porcentaje_avance || 0,
      estado_observacion: obs.estado_observacion || 'EN_PROCESO'
    }
  };
});

